import React, { useState, useRef, useEffect } from 'react';
import { useSpring, animated } from '@react-spring/web';
import { 
  X, 
  ArrowLeft, 
  Send, 
  Paperclip, 
  Smile, 
  MoreHorizontal,
  Phone,
  Video,
  Info,
  Minus
} from 'lucide-react';

const ConversationPanel = ({ 
  conversation, 
  isVisible, 
  onClose, 
  onBack,
  messages = []
}) => {
  const [isMinimized, setIsMinimized] = useState(false);
  const [newMessage, setNewMessage] = useState('');
  const messagesEndRef = useRef(null);

  // Animação do painel
  const panelAnimation = useSpring({
    transform: isVisible ? 'translateY(0%)' : 'translateY(100%)',
    opacity: isVisible ? 1 : 0,
    config: { tension: 300, friction: 30 }
  });

  // Animação da altura (minimizado/expandido)
  const heightAnimation = useSpring({
    height: isMinimized ? '60px' : '400px',
    config: { tension: 300, friction: 30 }
  });

  // Scroll automático para a última mensagem
  useEffect(() => {
    if (messagesEndRef.current && !isMinimized) {
      messagesEndRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [messages, isMinimized]);

  const handleSendMessage = () => {
    if (newMessage.trim()) {
      // Aqui você implementaria a lógica para enviar a mensagem
      console.log('Enviando mensagem:', newMessage);
      setNewMessage('');
    }
  };

  const handleKeyPress = (e) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSendMessage();
    }
  };

  const toggleMinimize = () => {
    setIsMinimized(!isMinimized);
  };

  if (!isVisible || !conversation) return null;

  return (
    <div className="fixed bottom-4 right-[340px] z-50">
      <animated.div
        style={{
          ...panelAnimation,
          ...heightAnimation,
          width: '320px'
        }}
        className="bg-neutral-800 border border-neutral-700 shadow-2xl rounded-lg overflow-hidden"
      >
        {/* Header */}
        <div className="bg-neutral-900 px-4 py-3 flex items-center justify-between border-b border-neutral-700">
          <div className="flex items-center space-x-3">
            <button
              onClick={onBack}
              className="p-1 text-gray-400 hover:text-white transition-colors"
            >
              <ArrowLeft className="h-4 w-4" />
            </button>
            <div className="relative">
              <img
                src={conversation.avatar}
                alt={conversation.name}
                className="w-8 h-8 rounded-full"
              />
              <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-900 ${
                conversation.status === 'online' ? 'bg-green-500' : 
                conversation.status === 'away' ? 'bg-orange-500' : 'bg-gray-500'
              }`} />
            </div>
            <div>
              <h3 className="text-white font-medium text-sm">{conversation.name}</h3>
              <p className="text-xs text-neutral-400">
                {conversation.status === 'online' ? 'Online' : 
                 conversation.status === 'away' ? 'Ausente' : 'Offline'}
              </p>
            </div>
          </div>
          <div className="flex items-center space-x-1">
            <button className="p-1 text-gray-400 hover:text-white transition-colors">
              <Phone className="h-4 w-4" />
            </button>
            <button className="p-1 text-gray-400 hover:text-white transition-colors">
              <Video className="h-4 w-4" />
            </button>
            <button
              onClick={toggleMinimize}
              className="p-1 text-gray-400 hover:text-white transition-colors"
            >
              <Minus className="h-4 w-4" />
            </button>
            <button
              onClick={onClose}
              className="p-1 text-gray-400 hover:text-white transition-colors"
            >
              <X className="h-4 w-4" />
            </button>
          </div>
        </div>

        {!isMinimized && (
          <>
            {/* Messages Area */}
            <div className="flex-1 overflow-y-auto p-3 space-y-3 max-h-[280px] bg-neutral-800">
              {messages.length === 0 ? (
                <div className="text-center text-neutral-400 py-8">
                  <p className="text-sm">Inicie uma conversa com {conversation.name}</p>
                </div>
              ) : (
                messages.map((message, index) => (
                  <div
                    key={index}
                    className={`flex ${message.isOwn ? 'justify-end' : 'justify-start'}`}
                  >
                    <div className={`max-w-[70%] ${message.isOwn ? 'order-2' : 'order-1'}`}>
                      {!message.isOwn && (
                        <img
                          src={conversation.avatar}
                          alt={conversation.name}
                          className="w-6 h-6 rounded-full mb-1"
                        />
                      )}
                      <div
                        className={`px-3 py-2 rounded-lg text-sm ${
                          message.isOwn
                            ? 'bg-blue-600 text-white rounded-br-sm'
                            : 'bg-neutral-700 text-white rounded-bl-sm'
                        }`}
                      >
                        <p>{message.text}</p>
                        <p className={`text-xs mt-1 ${
                          message.isOwn ? 'text-blue-200' : 'text-neutral-400'
                        }`}>
                          {message.timestamp}
                        </p>
                      </div>
                    </div>
                  </div>
                ))
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Message Input */}
            <div className="border-t border-neutral-700 p-3">
              <div className="flex items-end space-x-2">
                <button className="p-2 text-gray-400 hover:text-white transition-colors">
                  <Paperclip className="h-4 w-4" />
                </button>
                <div className="flex-1 relative">
                  <textarea
                    value={newMessage}
                    onChange={(e) => setNewMessage(e.target.value)}
                    onKeyPress={handleKeyPress}
                    placeholder="Digite uma mensagem..."
                    className="w-full bg-neutral-700 border border-neutral-600 rounded-lg px-3 py-2 text-white text-sm resize-none focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                    rows="1"
                    style={{ minHeight: '36px', maxHeight: '80px' }}
                  />
                </div>
                <button className="p-2 text-gray-400 hover:text-white transition-colors">
                  <Smile className="h-4 w-4" />
                </button>
                <button
                  onClick={handleSendMessage}
                  disabled={!newMessage.trim()}
                  className="p-2 text-blue-400 hover:text-blue-300 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                >
                  <Send className="h-4 w-4" />
                </button>
              </div>
            </div>
          </>
        )}
      </animated.div>
    </div>
  );
};

export default ConversationPanel;
